const DEFAULT_SOURCE: &str = r#"// COR24 C — UART hello + LED
void putc(int c) {
    *(char *)0xFF0100 = c;
}

void led_on() {
    *(char *)0xFF0000 = 0;
}

int main() {
    putc(72);   // H
    putc(105);  // i
    putc(33);   // !
    led_on();
    return 42;
}
"#;

